def test_bulk_import_non_csv_file_returns_415(
    hr_admin_session,  # <fixture>: authenticated requests.Session
    base_url,          # <fixture>: str
):
    json_payload = b'{"employee_id": "E099", "first_name": "Zara"}'
    files = {"file": ("employees.json", io.BytesIO(json_payload), "application/json")}
    resp = hr_admin_session.post(f"{base_url}/employees/import", files=files)

    assert resp.status_code == 415, (
        f"Expected 415 for non-CSV upload, got {resp.status_code}"
    )

import pytest
import io

def test_bulk_import_missing_required_header_returns_422(
    hr_admin_session,  # <fixture>: authenticated requests.Session
    base_url,          # <fixture>: str
):
    csv_data = (
        "employee_id,first_name,last_name\n"
        "E010,John,Doe\n"
    )
    files = {"file": ("employees.csv", io.BytesIO(csv_data.encode()), "text/csv")}
    resp = hr_admin_session.post(f"{base_url}/employees/import", files=files)

    assert resp.status_code == 422, (
        f"Expected 422 for missing header, got {resp.status_code}"
    )
    body = resp.json()
    detail = str(body)
    assert "email" in detail.lower(), (
        f"Expected 'email' cited in error detail, got: {detail}"
    )

import pytest
import io

RATE_LIMIT_THRESHOLD = <rate_limit_config>  # <helper_fn>: returns int from env/config

def _minimal_csv():
    return (
        "employee_id,first_name,last_name,email\n"
        "E030,Rate,Limit,rate@example.com\n"
    )

def test_bulk_import_rate_limit_triggers_after_threshold(
    hr_admin_session,      # <fixture>: authenticated requests.Session
    base_url,              # <fixture>: str
    reset_rate_limit,      # <fixture>: resets rate-limit counters before test
    cleanup_employees,     # <fixture>: callable(list[str])
):
    url = f"{base_url}/employees/import"
    for i in range(RATE_LIMIT_THRESHOLD):
        files = {"file": ("e.csv", io.BytesIO(_minimal_csv().encode()), "text/csv")}
        r = hr_admin_session.post(url, files=files)
        assert r.status_code in (200, 207), f"Request {i+1} failed early: {r.status_code}"

    files = {"file": ("e.csv", io.BytesIO(_minimal_csv().encode()), "text/csv")}
    throttled = hr_admin_session.post(url, files=files)
    assert throttled.status_code == 429, (
        f"Expected 429 after {RATE_LIMIT_THRESHOLD} requests, got {throttled.status_code}"
    )
    assert "retry-after" in {k.lower() for k in throttled.headers}
    cleanup_employees(["E030"])
